__global__ void 
lud_diagonal(float *m, int matrix_dim, int offset)
{
  int i, j;
  float shadow[BLOCK_SIZE][BLOCK_SIZE];

  int array_offset = offset * matrix_dim + offset;
  int tx = get_global_id(0);

  // Load diagonal block into shared memory (simulated via local array)
  for (i = 0; i < BLOCK_SIZE; i++) {
    shadow[i][tx] = m[array_offset + tx];
    array_offset += matrix_dim;
  }

  // LUD computation on the diagonal block
  for (i = 0; i < BLOCK_SIZE - 1; i++) {
    if (tx > i) {
      float sum = 0.0f;
      for (j = 0; j < i; j++) {
        sum += shadow[tx][j] * shadow[j][i];
      }
      shadow[tx][i] -= sum;
      shadow[tx][i] /= shadow[i][i];
    }

    if (tx > i) {
      float sum = 0.0f;
      for (j = 0; j < i + 1; j++) {
        sum += shadow[i + 1][j] * shadow[j][tx];
      }
      shadow[i + 1][tx] -= sum;
    }
  }

  // Write back results
  array_offset = (offset + 1) * matrix_dim + offset;
  for (i = 1; i < BLOCK_SIZE; i++) {
    m[array_offset + tx] = shadow[i][tx];
    array_offset += matrix_dim;
  }
}

__global__ void
lud_perimeter(float *m, int matrix_dim, int offset)
{
  float dia[BLOCK_SIZE][BLOCK_SIZE];
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];

  int i, j, array_offset;
  int idx;
  int tid = get_global_id(0);
  int blk_idx = get_group_id(0);

  if (tid < BLOCK_SIZE) {
    idx = tid;

    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE / 2; i++) {
      dia[i][idx] = m[array_offset + idx];
      array_offset += matrix_dim;
    }

    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
      peri_row[i][idx] = m[array_offset + (blk_idx + 1) * BLOCK_SIZE + idx];
      array_offset += matrix_dim;
    }
  } else {
    idx = tid - BLOCK_SIZE;

    array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
    for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
      dia[i][idx] = m[array_offset + idx];
      array_offset += matrix_dim;
    }

    array_offset = (offset + (blk_idx + 1) * BLOCK_SIZE) * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
      peri_col[i][idx] = m[array_offset + idx];
      array_offset += matrix_dim;
    }
  }

  // Compute perimeter rows
  if (tid < BLOCK_SIZE) { 
    idx = tid;
    for (i = 1; i < BLOCK_SIZE; i++) {
      float sum = 0.0f;
      for (j = 0; j < i; j++) {
        sum += dia[i][j] * peri_row[j][idx];
      }
      peri_row[i][idx] -= sum;
    }
  } else { 
    // Compute perimeter cols
    idx = tid - BLOCK_SIZE;
    for (i = 0; i < BLOCK_SIZE; i++) {
      float sum = 0.0f;
      for (j = 0; j < i; j++) {
        sum += peri_col[idx][j] * dia[j][i];
      }
      peri_col[idx][i] -= sum;
      peri_col[idx][i] /= dia[i][i];
    }
  }

  // Write back results
  if (tid < BLOCK_SIZE) { 
    idx = tid;
    array_offset = (offset + 1) * matrix_dim + offset;
    for (i = 1; i < BLOCK_SIZE; i++) {
      m[array_offset + (blk_idx + 1) * BLOCK_SIZE + idx] = peri_row[i][idx];
      array_offset += matrix_dim;
    }
  } else { 
    idx = tid - BLOCK_SIZE;
    array_offset = (offset + (blk_idx + 1) * BLOCK_SIZE) * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
      m[array_offset + idx] = peri_col[i][idx];
      array_offset += matrix_dim;
    }
  }
}

__global__ void
lud_internal(float *m, int matrix_dim, int offset)
{
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];

  int i;
  float sum;

  int gx = get_group_id(0);
  int gy = get_group_id(1);
  int tx = get_local_id(0);
  int ty = get_local_id(1);

  int global_row_id = offset + (gy + 1) * BLOCK_SIZE;
  int global_col_id = offset + (gx + 1) * BLOCK_SIZE;

  peri_row[ty][tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
  peri_col[ty][tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];

  sum = 0.0f;
  for (i = 0; i < BLOCK_SIZE; i++) {
    sum += peri_col[ty][i] * peri_row[i][tx];
  }
  m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
}
